// 計算今日日期（台灣時間 UTC+8）
const now = new Date();
const taiwanOffset = 8 * 60 * 60 * 1000;
const twDate = new Date(now.getTime() + taiwanOffset);

const yyyy = twDate.getUTCFullYear();
const mm = String(twDate.getUTCMonth() + 1).padStart(2, '0');
const dd = String(twDate.getUTCDate()).padStart(2, '0');

const isoDate = `${yyyy}-${mm}-${dd}`; // e.g. 2026-05-01
const xlsName = `${yyyy}_${mm}_${dd}.xls`; // e.g. 2026_05_01.xls
const xlsUrl  = `https://www.taoyuanairport.com.tw/flightforecast/${xlsName}`;

return [{ json: { isoDate, xlsName, xlsUrl } }];

// ─── 解析桃園機場 XLS ─────────────────────────────────────
// 預期格式（可能因官網改版而不同，請依實際情況調整）：
//   Row 0: 標題列（忽略）
//   Col A: 時段（0, 1, 2, ... 23 或 "00", "01", ...）
//   Col B: 第一航廈 入境
//   Col C: 第一航廈 出境
//   Col D: 第二航廈 入境
//   Col E: 第二航廈 出境
// 若 XLS 格式不同，調整 COLUMN_MAP 與 skipRows 即可。

const XLSX = require('xlsx');

const binaryData = $binary.data; // n8n 二進位欄位
const buffer = Buffer.from(binaryData, 'base64');

const workbook = XLSX.read(buffer, { type: 'buffer' });
const sheetName = workbook.SheetNames[0];
const sheet = workbook.Sheets[sheetName];
const rows = XLSX.utils.sheet_to_json(sheet, { header: 1, defval: 0 });

// 跳過標題列（根據實際 XLS 調整）
const skipRows = 1;
const dataRows = rows.slice(skipRows);

const hours = [];

for (let i = 0; i < dataRows.length; i++) {
  const row = dataRows[i];
  const hourRaw = row[0];
  const hour = parseInt(String(hourRaw), 10);
  if (isNaN(hour) || hour < 0 || hour > 23) continue;

  // 各欄位加總（T1入境 + T1出境 + T2入境 + T2出境）
  const t1Arr = Number(row[1]) || 0;
  const t1Dep = Number(row[2]) || 0;
  const t2Arr = Number(row[3]) || 0;
  const t2Dep = Number(row[4]) || 0;

  hours.push({
    hour,
    forecastCount: t1Arr + t1Dep + t2Arr + t2Dep,
    terminal: 'all',
  });
}

// 確保 24 小時都有資料
const filled = Array.from({ length: 24 }, (_, h) => {
  const found = hours.find((r) => r.hour === h);
  return found ?? { hour: h, forecastCount: 0, terminal: 'all' };
});

const isoDate = $('計算日期與 XLS URL').first().json.isoDate;
const xlsName = $('計算日期與 XLS URL').first().json.xlsName;

return [{
  json: {
    date: isoDate,
    sourceFile: xlsName,
    hours: filled,
  }
}];

